"""Chat consumer for streaming Ollama responses over WebSocket."""

import json
import logging
from typing import Any

from channels.generic.websocket import AsyncWebsocketConsumer

from .services import OllamaService

logger = logging.getLogger(__name__)


class ChatConsumer(AsyncWebsocketConsumer):
    """WebSocket consumer for chat streaming."""

    def __init__(self) -> None:
        super().__init__()
        self.ollama_service: OllamaService | None = None

    async def connect(self) -> None:
        session_id = self.scope.get("session", {}).get("session_key") or "anonymous"
        self.ollama_service = OllamaService()
        await self.accept()
        await self.send(
            text_data=json.dumps({"type": "connected", "session_id": session_id})
        )
        logger.info("WebSocket connected: %s", session_id)

    async def disconnect(self, close_code: int) -> None:
        if self.ollama_service:
            await self.ollama_service.close()
        logger.info("WebSocket disconnected: %s", close_code)

    async def receive(
        self, text_data: str | None = None, bytes_data: bytes | None = None
    ) -> None:
        if not text_data:
            return

        try:
            data = json.loads(text_data)
        except json.JSONDecodeError:
            await self.send(
                text_data=json.dumps({"type": "error", "message": "Invalid JSON"})
            )
            return

        message_type = data.get("type", "")

        if message_type == "chat":
            await self._handle_chat(data)
        else:
            await self.send(
                text_data=json.dumps(
                    {
                        "type": "error",
                        "message": f"Unknown message type: {message_type}",
                    }
                )
            )

    async def _handle_chat(self, data: dict[str, Any]) -> None:
        prompt = data.get("prompt", "")
        if not prompt:
            await self.send(
                text_data=json.dumps({"type": "error", "message": "Empty prompt"})
            )
            return

        if not self.ollama_service:
            await self.send(
                text_data=json.dumps(
                    {"type": "error", "message": "Service not initialized"}
                )
            )
            return

        await self.send(
            text_data=json.dumps({"type": "status", "message": "Thinking..."})
        )

        full_response = ""
        async for token in self.ollama_service.stream_chat(prompt):
            full_response += token
            await self.send(
                text_data=json.dumps(
                    {"type": "token", "content": token, "full_response": full_response}
                )
            )

        await self.send(
            text_data=json.dumps({"type": "done", "full_response": full_response})
        )

