/**
 * Ollama Chat WebSocket client
 * Handles streaming tokens from Ollama via Django Channels WebSocket
 */

(function() {
    'use strict';

    const WS_PROTOCOL = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const WS_URL = `${WS_PROTOCOL}//${window.location.host}/ws/chat/`;

    let socket = null;
    let isConnected = false;
    let currentResponseElement = null;
    let fullResponse = '';

    // DOM elements
    const chatForm = document.getElementById('chat-form');
    const promptInput = document.getElementById('prompt-input');
    const sendButton = document.getElementById('send-button');
    const chatContainer = document.getElementById('chat-container');
    const connectionStatus = document.getElementById('connection-status');

    /**
     * Update connection status indicator
     */
    function updateStatus(status, message) {
        connectionStatus.textContent = message;
        connectionStatus.className = `text-sm ${status === 'connected' ? 'status-connected' : status === 'disconnected' ? 'status-disconnected' : 'status-connecting'}`;
    }

    /**
     * Append a user message to the chat
     */
    function appendUserMessage(content) {
        const msgDiv = document.createElement('div');
        msgDiv.className = 'message user';
        msgDiv.innerHTML = `<div class="message-role text-xs text-blue-200 mb-1 uppercase">User</div><div class="message-content">${escapeHtml(content)}</div>`;
        chatContainer.appendChild(msgDiv);
        scrollToBottom();
        return msgDiv;
    }

    /**
     * Show thinking indicator while waiting for response
     */
    function showThinkingIndicator() {
        const thinkingDiv = document.createElement('div');
        thinkingDiv.className = 'thinking';
        thinkingDiv.id = 'thinking-indicator';
        thinkingDiv.innerHTML = `
            <div class="thinking-dots">
                <span></span><span></span><span></span>
            </div>
            <span class="text-sm text-gray-400">Thinking...</span>
        `;
        chatContainer.appendChild(thinkingDiv);
        scrollToBottom();
        return thinkingDiv;
    }

    /**
     * Remove thinking indicator
     */
    function removeThinkingIndicator() {
        const indicator = document.getElementById('thinking-indicator');
        if (indicator) {
            indicator.remove();
        }
    }

    /**
     * Append or update the assistant's streamed response
     */
    function updateAssistantMessage(token, fullText) {
        if (!currentResponseElement) {
            currentResponseElement = document.createElement('div');
            currentResponseElement.className = 'message assistant';
            currentResponseElement.innerHTML = '<div class="message-role text-xs text-gray-500 mb-1 uppercase">Assistant</div><div class="message-content"></div>';
            chatContainer.appendChild(currentResponseElement);
        }
        currentResponseElement.querySelector('.message-content').innerHTML = escapeHtml(fullText).replace(/\n/g, '<br>');
        scrollToBottom();
    }

    /**
     * Scroll chat to bottom
     */
    function scrollToBottom() {
        chatContainer.scrollTop = chatContainer.scrollHeight;
    }

    /**
     * Escape HTML to prevent XSS
     */
    function escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    /**
     * Connect to WebSocket
     */
    function connect() {
        socket = new WebSocket(WS_URL);

        socket.onopen = function() {
            isConnected = true;
            updateStatus('connected', 'Connected');
            sendButton.disabled = false;
        };

        socket.onmessage = function(event) {
            const data = JSON.parse(event.data);
            handleMessage(data);
        };

        socket.onerror = function(error) {
            console.error('WebSocket error:', error);
            updateStatus('disconnected', 'Connection error');
        };

        socket.onclose = function(event) {
            isConnected = false;
            updateStatus('disconnected', `Disconnected (code: ${event.code})`);
            sendButton.disabled = true;
            // Attempt to reconnect after 3 seconds
            setTimeout(connect, 3000);
        };
    }

    /**
     * Handle incoming WebSocket messages
     */
    function handleMessage(data) {
        const type = data.type || '';

        switch (type) {
            case 'connected':
                console.log('Chat connected, session:', data.session_id);
                break;

            case 'status':
                if (data.message === 'Thinking...') {
                    removeThinkingIndicator();
                    showThinkingIndicator();
                }
                break;

            case 'token':
                removeThinkingIndicator();
                fullResponse = data.full_response || '';
                updateAssistantMessage(data.content, fullResponse);
                break;

            case 'done':
                removeThinkingIndicator();
                currentResponseElement = null;
                fullResponse = '';
                promptInput.value = '';
                sendButton.disabled = false;
                break;

            case 'error':
                removeThinkingIndicator();
                console.error('Chat error:', data.message);
                alert('Error: ' + data.message);
                sendButton.disabled = false;
                break;
        }
    }

    /**
     * Send a chat message
     */
    function sendMessage(prompt) {
        if (!isConnected) {
            alert('Not connected to chat server. Please wait for connection...');
            return;
        }

        if (!prompt.trim()) {
            return;
        }

        sendButton.disabled = true;
        appendUserMessage(prompt);

        socket.send(JSON.stringify({
            type: 'chat',
            prompt: prompt
        }));
    }

    // Event listeners
    chatForm.addEventListener('submit', function(e) {
        e.preventDefault();
        const prompt = promptInput.value;
        sendMessage(prompt);
    });

    // Initialize
    updateStatus('connecting', 'Connecting...');
    sendButton.disabled = true;
    connect();
})();

